func NewHandler(logger *slog.Logger, metricMeter metric.Meter, publisher eventbus.Publisher, config HandlerConfig) (flushhandler.FlushEventHandler, error) {
	if err := config.Validate(); err != nil {
		return nil, err
	}
	h := &handler{publisher: publisher, logger: logger, config: config}
	return flushhandler.NewFlushEventHandler(flushhandler.FlushEventHandlerOptions{
		Name:        "ingest_notification",
		Callback:    h.OnFlushSuccess,
		Logger:      logger,
		MetricMeter: metricMeter,
	})
}
